import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as r,c as s,a as e,e as t,d,f as c}from"./app-7b80e4d2.js";const h={},i=e("h1",{id:"新版vscode中python设置自动补全函数括号",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#新版vscode中python设置自动补全函数括号","aria-hidden":"true"},"#"),t(" 新版VSCode中Python设置自动补全函数括号")],-1),l={href:"https://blog.csdn.net/w11231/article/details/123586558",target:"_blank",rel:"noopener noreferrer"},_=c('<h1 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h1><p>在网上能找到的关于如何让VSCode中Python自动补全函数括号的方法都是同样的，但基本上都是几年前的方法了，在VSCode更新后引入了Pylance，使得之前的设置项不存在了。在自己摸索了很久后终于发现了相同功能的选项👇</p><p>如果不确定自己用的哪种，可以都试一下，在Settings.json中如果有不存在的设置项会报错</p><h2 id="一、旧版的方法-jedi" tabindex="-1"><a class="header-anchor" href="#一、旧版的方法-jedi" aria-hidden="true">#</a> 一、旧版的方法(Jedi)</h2><p>设置文件settings.json中添加&quot;python.autoComplete.addBrackets&quot;: true</p><h2 id="二、新版的方法-pylance" tabindex="-1"><a class="header-anchor" href="#二、新版的方法-pylance" aria-hidden="true">#</a> 二、新版的方法(Pylance)</h2><p>设置 -&gt; 扩展 -&gt; Pylance -&gt; 将 python.analysis.completeFunctionParens 下方的选项打勾<br> 或着<br> 直接在settings.json中添加&quot;python.analysis.completeFunctionParens&quot;: true</p><h2 id="提示" tabindex="-1"><a class="header-anchor" href="#提示" aria-hidden="true">#</a> 提示</h2><p>这里说的自动补全函数括号是指，在输入完函数回车后，VSCode默认只会补全函数，但函数后面没有括号。当开启上面的设置后输入函数再回车，将会给补全的函数自动加上括号</p>',9);function p(u,f){const a=o("ExternalLinkIcon");return r(),s("div",null,[i,e("blockquote",null,[e("p",null,[e("a",l,[t("https://blog.csdn.net/w11231/article/details/123586558"),d(a)])])]),_])}const b=n(h,[["render",p],["__file","新版VSCode中Python设置自动补全函数括号.html.vue"]]);export{b as default};
